previewCss:
.darma-loader-uiverse-angle-bracket-reveal {
  font-size: 2em;
  font-weight: 900;
}
.darma-loader-uiverse-angle-bracket-reveal > * {
  color: black;
}
.darma-loader-uiverse-angle-bracket-reveal span {
  display: inline-flex;
}
.darma-loader-uiverse-angle-bracket-reveal span:nth-child(2) {
  letter-spacing: -1em;
  overflow: hidden;
  animation: darma-loader-uiverse-angle-bracket-reveal-reveal 1500ms cubic-bezier(0.645, 0.045, 0.355, 1) infinite
    alternate;
}
@keyframes darma-loader-uiverse-angle-bracket-reveal-reveal {
  0%,
  100% {
    opacity: 0.5;
    letter-spacing: -1em;
  }
  50% {
    opacity: 1;
    letter-spacing: 0em;
  }
}

